// 前缀线性基
class XorBase {
private:
	array<int, 21> a;    // 线性基基底
	array<int, 21> pos;  // 基底对应最晚出现的下标 
	static constexpr int MN = 20;
public:
	XorBase() { 
      fill(a.begin(), a.end(), 0);
      fill(pos.begin(), pos.end(), 0);
    };

	int& operator[](int x) {
		return a[x];
	}

	// 插入新数
	void insert(int x, int idx) {
		if (!x)return;
		for (int i = MN; i >= 0; i--)
			if (x & (1ll << i)) {
				if (!a[i]) {
					// 线性基里没有 x，插入 x
					a[i] = x;
					pos[i] = idx;
					return;
				}
				// 【重点】：新下标放在高位，老下标去低位
				if (idx > pos[i]) {
					swap(idx, pos[i]);
					swap(x, a[i]);
				}
				x ^= a[i]; // 线性基里有 x
			}
	}

	// 查最大
	int qmax(int L) {
		int res = 0;
		for (int i = MN; i >= 0; i--) {
			if (pos[i] >= L)
				res = max(res, res ^ a[i]);
		}
		return res;
	}
};
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var pre = vector<XorBase>(n + 1);
	fa(i, 1, n) {
		pre[i] = pre[i - 1];
		pre[i].insert(a[i], i);
	}
	int q; cin >> q;
	while (q--) {
		int l, r; cin >> l >> r;
		cout << pre[r].qmax(l) << endl;
	}
	return;
}

template <class Info>
class OfflineCatTree {
public:
	struct Query {
		int l, r, id;
	};

	int n;
	vector<Info> info;  // 存储原始数据 (下标 1 ~ n)
	vector<Query> qs;   // 存储询问
	vector<Info> ans;   // 存储最终算出的 Info
	vector<Info> tmp;   // O(N) 的全局缓存，用于计算前缀/后缀

	void init(int _n) {
		n = _n;
		info.assign(n + 1, Info());
		tmp.resize(n + 1);
		qs.clear();
	}

	void init(vector<Info>& _init) {
		n = _init.size() - 1;
		info = move(_init);
		tmp.resize(n + 1);
		qs.clear();
	}

	OfflineCatTree() : n(0) {}
	OfflineCatTree(int _n) { init(_n); }
	OfflineCatTree(vector<Info>& _init) { init(_init); }

	// 添加询问
	void add_query(int l, int r, int id) {
		qs.push_back({ l, r, id });
	}

	// 核心处理函数，返回所有询问的结果
	vector<Info>& solve() {
		if (qs.empty()) return ans;

		// 找到最大的 id 以调整答案数组大小
		int max_id = 0;
		for (const auto& q : qs)max_id = max(max_id, q.id);
		ans.assign(max_id + 1, Info());

		solve(1, n, qs);
		return ans;
	}

private:
	// 离线分治：利用递归特性，算完一层扔一层，空间 O(N)
	// 只要题目允许离线，离线猫树全面优于在线猫树，它保留了 O(1) 的合并次数，同时把空间降到了最低。
	// 若强制在线，使用线段树
	void solve(int l, int r, vector<Query>& q_curr) {
		if (q_curr.empty()) return;

		// 叶子节点：直接由 info[l] 贡献
		if (l == r) {
			for (const auto& q : q_curr) {
				ans[q.id] = info[l];
			}
			return;
		}

		int mid = (l + r) >> 1;

		// --- 1. 预处理中间向两边的前缀/后缀 ---
		// 注意：这里复用了 tmp 数组，省内存

		// [mid, l] 后缀：从 mid 向左
		// tmp[i] = info[i] + tmp[i + 1]
		// Info 合并方向：(左边) + (右边)
		tmp[mid] = info[mid];
		for (int i = mid - 1; i >= l; i--) {
			tmp[i] = info[i] + tmp[i + 1];
		}

		// [mid + 1, r] 前缀：从 mid + 1 向右
		// tmp[i] = tmp[i - 1] + info[i]
		if (mid + 1 <= r) {
			tmp[mid + 1] = info[mid + 1];
			for (int i = mid + 2; i <= r; i++) {
				tmp[i] = tmp[i - 1] + info[i];
			}
		}

		// --- 2. 处理询问 ---
		vector<Query> q_left, q_right;
		// 预留空间稍微优化一点常数，不写也没事
		q_left.reserve(q_curr.size() / 2);
		q_right.reserve(q_curr.size() / 2);

		for (const auto& q : q_curr) {
			if (q.r <= mid) {
				q_left.push_back(q);
			}
			else if (q.l > mid) {
				q_right.push_back(q);
			}
			else {
				// 跨越 mid 的询问
				// Ans = Suffix[l] + Prefix[r]
				ans[q.id] = tmp[q.l] + tmp[q.r];
			}
		}

		// 释放当前层内存
		q_curr.clear();

		// --- 3. 递归 ---
		solve(l, mid, q_left);
		solve(mid + 1, r, q_right);
	}
};

class XorBase {
private:
	array<int, 21> a; // 线性基基底
	static constexpr int MN = 20;
public:
	XorBase() { fill(a.begin(), a.end(), 0); };

	int& operator[](int x) {
		return a[x];
	}

	// 插入新数
	void insert(int x) {
		if (!x)return;
		for (int i = MN; i >= 0; i--)
			if (x & (1ll << i)) {
				if (!a[i]) {
					// 线性基里没有 x，插入 x
					a[i] = x;
					return;
				}
				x ^= a[i]; // 线性基里有 x
			}
	}

	// 查最大
	int qmax() {
		int res = 0;
		for (int i = MN; i >= 0; i--)
			res = max(res, res ^ a[i]);
		return res;
	}
};

struct Info {
	Info() {};
	Info(int x) { xb.insert(x); };

	mutable XorBase xb;
	int query_ans() const {
		return xb.qmax();
	}
};

Info operator+(const Info& a, const Info& b) {
	Info res = a; // 拷贝左边
	for (int i = 0; i <= 20; i++) {
		if (b.xb[i]) res.xb.insert(b.xb[i]); // 把右边插进去
	}
	return res;
}

void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<Info>(n + 1);
	fa(i, 1, n) {
		int x; cin >> x;
		a[i] = Info(x);
	}
	var hachimi = OfflineCatTree<Info>(a);
	int q; cin >> q;
	fa(i, 1, q) {
		int l, r; cin >> l >> r;
		hachimi.add_query(l, r, i);
	}
	var ans = hachimi.solve();
	fa(i, 1, q)cout << ans[i].query_ans() << endl;
	return;
}
